eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   naturalCausalityText: () => (/* binding */ naturalCausalityText),\n/* harmony export */   practiceTiers: () => (/* binding */ practiceTiers)\n/* harmony export */ });\nconst practiceTiers = [\n    {\n        key: \"body\",\n        title: \"K\\xd6RPER\",\n        subtitle: \"Das Gef\\xe4\\xdf\",\n        concept: \"Der K\\xf6rper ist der Tempel der Seele. Ohne ein stabiles, vitales Gef\\xe4\\xdf kann die Seele nicht vollst\\xe4ndig durch den Menschen wirken.\",\n        colorClass: \"from-amber-500/35 to-red-500/30 border-amber-300/45\",\n        resonanceTooltip: \"Resonanz: Vitalit\\xe4t, Klarheit, geerdete Pr\\xe4senz.\",\n        dissonanceTooltip: \"Dissonanz: Tr\\xe4gheit, Entz\\xfcndung, blockierte Lebensenergie.\",\n        sections: [\n            {\n                title: \"Vitalit\\xe4t & Gesundheit\",\n                bullets: [\n                    \"Schlaf als h\\xf6chste Regenerationspraxis bewusst pflegen\",\n                    \"Bewegung t\\xe4glich — nicht als Pflicht, sondern als Ausdruck von Lebendigkeit\",\n                    \"Krafttraining zum Aufbau und Erhalt der Muskulatur\",\n                    \"Ausdauer f\\xfcr Herz, Lunge und Nervensystem\"\n                ]\n            },\n            {\n                title: \"Ern\\xe4hrung & inneres \\xd6kosystem\",\n                bullets: [\n                    \"Nahrung als Information f\\xfcr K\\xf6rper und Geist verstehen\",\n                    \"Darmgesundheit pflegen: Fermentation, Ballaststoffe, lebendige Lebensmittel\",\n                    \"Entz\\xfcndungsarme, n\\xe4hrstoffreiche Ern\\xe4hrung als Grundlage geistiger Klarheit\",\n                    \"Bewusstes Fasten zur Reinigung und Selbstwahrnehmung\"\n                ]\n            },\n            {\n                title: \"K\\xf6rperbewusstsein\",\n                bullets: [\n                    \"Den eigenen K\\xf6rper kennen: Organe, Nervensystem, hormonelles System\",\n                    \"Stresssignale fr\\xfch erkennen und regulieren\",\n                    \"Atem als direktes Werkzeug zwischen K\\xf6rper und Geist nutzen\"\n                ]\n            },\n            {\n                title: \"Schmerz & Krankheit als Seelenlektion\",\n                bullets: [\n                    \"K\\xf6rperliche Leiden nicht nur bek\\xe4mpfen, sondern zuerst verstehen — was will diese Erfahrung zeigen?\",\n                    \"Krankheit als m\\xf6gliche bewusst gew\\xe4hlte Lektion der Seele respektieren\",\n                    \"Schmerz als Lehrmeister annehmen, ohne im Leiden zu verharren\"\n                ]\n            },\n            {\n                title: \"Sexualit\\xe4t & Lebensenergie\",\n                bullets: [\n                    \"Sexuelle Energie als eine der st\\xe4rksten Lebenskr\\xe4fte bewusst wahrnehmen\",\n                    \"Lebensenergie nicht gedankenlos zerstreuen, sondern bewusst f\\xfchren und kanalisieren\",\n                    \"Sexualit\\xe4t als Ausdruck von Verbindung und Sch\\xf6pfung verstehen — nicht prim\\xe4r als Triebbefriedigung\"\n                ]\n            }\n        ],\n        resonance: [\n            \"Stabiler Schlafrhythmus und regelm\\xe4\\xdfige Bewegung\",\n            \"N\\xe4hrstoffreiche, entz\\xfcndungsarme Ern\\xe4hrung\",\n            \"Atemarbeit und fr\\xfche Stressregulation\",\n            \"Verantwortlicher Umgang mit sexueller Energie\"\n        ],\n        dissonance: [\n            \"Chronischer Schlafmangel und Bewegungsarmut\",\n            \"Digitale \\xdcberstimulation beim Essen, \\xdcberkonsum\",\n            \"Ignorierte K\\xf6rpersignale und verdr\\xe4ngter Schmerz\",\n            \"Gedankenlose Zerstreuung von Lebensenergie\"\n        ]\n    },\n    {\n        key: \"mind\",\n        title: \"GEIST\",\n        subtitle: \"Das Werkzeug\",\n        concept: \"Der Geist ist kein Feind — er ist das pr\\xe4ziseste Werkzeug der Seele. Seelenmeisterschaft bedeutet, ihn zu schulen, nicht ihn zu unterdr\\xfccken.\",\n        colorClass: \"from-cyan-500/30 to-blue-500/30 border-cyan-300/45\",\n        resonanceTooltip: \"Resonanz: Fokus, Unterscheidungskraft, geistige Souver\\xe4nit\\xe4t.\",\n        dissonanceTooltip: \"Dissonanz: Reaktivit\\xe4t, Zerstreuung, Konditionierungs-Schleifen.\",\n        sections: [\n            {\n                title: \"Psychologisches Fundament\",\n                bullets: [\n                    \"Grundwissen in Psychologie, P\\xe4dagogik und Hirnforschung aufbauen\",\n                    \"Eigene Konditionierungen, Glaubenss\\xe4tze und Traumata erkennen und aufl\\xf6sen\",\n                    \"Das Ego als n\\xfctzliches Werkzeug f\\xfchren — nicht von ihm gef\\xfchrt werden\",\n                    \"M\\xfcndigkeit und kommunikative Reife stetig weiterentwickeln\"\n                ]\n            },\n            {\n                title: \"Dopamin-Balance & Geisteshygiene\",\n                bullets: [\n                    \"Bewusster Umgang mit digitalen Stimuli: soziale Medien, Serien, Pornografie, \\xdcberkonsum\",\n                    \"Die Langeweile umarmen lernen — sie ist der Eingang zur Stille der Seele\",\n                    \"Belohnungsaufschub kultivieren als Zeichen innerer Reife\",\n                    \"Dopaminquellen bewusst w\\xe4hlen: Sch\\xf6pfung statt Konsum\"\n                ]\n            },\n            {\n                title: \"Wissensfelder des Geistes\",\n                bullets: [\n                    \"Nahtoderfahrungen, Reinkarnationsforschung (Newton, Stevenson, Weiss u.a.) studieren\",\n                    \"Quantenphysik und ihre spirituellen Implikationen verstehen\",\n                    \"Astronomie und Naturwissenschaft als Staunen-Praxis\",\n                    \"\\xd6sterreichische \\xd6konomie als Fundament souver\\xe4ner Gesellschaftsorganisation\",\n                    \"Bitcoin als dezentrales, ehrliches Geldsystem f\\xfcr eine freie Zivilisation begreifen\"\n                ]\n            },\n            {\n                title: \"Schattenarbeit\",\n                bullets: [\n                    \"Die abgelehnten, verdr\\xe4ngten und besch\\xe4mten Teile des Selbst aktiv aufsuchen\",\n                    \"Eigene Wiederholungsmuster in Beziehungen, Konflikten und Selbstsabotage erkennen\",\n                    \"Den Schatten nicht bek\\xe4mpfen, sondern integrieren — er tr\\xe4gt verborgene Kraft\",\n                    \"Therapeutische Unterst\\xfctzung als Zeichen von St\\xe4rke, nicht Schw\\xe4che annehmen\"\n                ]\n            },\n            {\n                title: \"Dienst durch Wissen\",\n                bullets: [\n                    \"Hilfe an Hilfsbed\\xfcrftige: Kinder, Kranke, Alte, Menschen mit Behinderung\",\n                    \"Wissen teilen, ohne zu missionieren\",\n                    \"Spenden oder aktive F\\xfcrsorge als Ausdruck von F\\xfclle, nicht Pflicht\"\n                ]\n            }\n        ],\n        resonance: [\n            \"Ehrliche Selbstreflexion und klare Verantwortungs\\xfcbernahme\",\n            \"Digitale Hygiene und Belohnungsaufschub\",\n            \"Schattenintegration statt Verdr\\xe4ngung\",\n            \"Wissensaufbau mit Dienstorientierung\"\n        ],\n        dissonance: [\n            \"Digitale \\xdcberstimulation und Pornografie\",\n            \"Rationalisierung ohne innere Arbeit\",\n            \"Unintegrierter Schatten und Selbstsabotage\",\n            \"Wissen als Ego-Dekoration statt Dienst\"\n        ]\n    },\n    {\n        key: \"soul\",\n        title: \"SEELE\",\n        subtitle: \"Das Wesen\",\n        concept: \"Die Seele ist nicht etwas, das man entwickelt — sie ist das, was man ist. Seelenpraxis bedeutet, die Schichten abzutragen, die sie verdecken.\",\n        colorClass: \"from-soul-gold/35 to-zinc-100/25 border-soul-gold/50\",\n        resonanceTooltip: \"Resonanz: Einheit, Mitgef\\xfchl, intuitive F\\xfchrung.\",\n        dissonanceTooltip: \"Dissonanz: Trennungserleben, Ego-Impuls, innere Taubheit.\",\n        sections: [\n            {\n                title: \"Stille & Achtsamkeit\",\n                bullets: [\n                    \"Meditation als t\\xe4gliche Grundpraxis — nicht als Technik, sondern als Heimkehr\",\n                    \"Achtsamkeit im Alltag: vollst\\xe4ndige Pr\\xe4senz in einfachen Momenten\",\n                    \"Stille aktiv suchen und aushalten lernen\"\n                ]\n            },\n            {\n                title: \"Mitgef\\xfchl & Liebe als Praxis\",\n                bullets: [\n                    \"Mitgef\\xfchlsmeditationen (Metta, Loving-Kindness) als regelm\\xe4\\xdfige \\xdcbung\",\n                    \"Aktiv Liebesgef\\xfchle nach au\\xdfen investieren: Menschen, Tiere, Natur, Pflanzen, Pilze, das Universum\",\n                    \"Den anderen als Seele sehen — auch in Konflikten\"\n                ]\n            },\n            {\n                title: \"Die bewusste \\xdcbung des freien Willens\",\n                bullets: [\n                    \"T\\xe4glich kleine Momente bewusst wahrnehmen, in denen man gegen den Impuls des Egos w\\xe4hlt\",\n                    \"Den freien Willen als heiliges Werkzeug der Seele verstehen — nicht als Freiheit des Egos\",\n                    \"Jede bewusste Wahl im Dienst der Seele als Akt der Seelenmeisterschaft feiern\"\n                ]\n            },\n            {\n                title: \"Kreativit\\xe4t als Seelenausdruck\",\n                bullets: [\n                    \"Einen kreativen Kanal finden und regelm\\xe4\\xdfig leben: Schreiben, Musik, Handwerk, Kunst\",\n                    \"Sch\\xf6pfen als spirituelle Praxis begreifen — jede Sch\\xf6pfung ist ein Ausdruck der Seele\"\n                ]\n            },\n            {\n                title: \"Die innere Sprache der Seele\",\n                bullets: [\n                    \"Tr\\xe4ume, Symbole, Synchronizit\\xe4ten und Intuitionen als Seelenkommunikation ernst nehmen\",\n                    \"Ein Traumtagebuch oder Symboljournal f\\xfchren\",\n                    \"Innere Bilder und Impulse nicht sofort rational aufl\\xf6sen — erst f\\xfchlen, dann verstehen\"\n                ]\n            },\n            {\n                title: \"Kosmisches Bewusstsein als Zielzustand\",\n                bullets: [\n                    \"Das Wissen um die Einheit aller Seelen nicht nur als Konzept kennen, sondern als Wahrnehmungshintergrund des Alltags kultivieren\",\n                    \"Den Moment erkennen, wenn man aus dem Einheitsbewusstsein herausf\\xe4llt — und bewusst zur\\xfcckkehren\",\n                    \"Das Leben aus der Perspektive der Seele f\\xfchren: Was w\\xfcrde meine Seele in diesem Moment w\\xe4hlen?\"\n                ]\n            }\n        ],\n        resonance: [\n            \"T\\xe4gliche Stillepraxis und meditative Heimkehr\",\n            \"Mitgef\\xfchl im Konflikt statt Urteil\",\n            \"Bewusste Entscheidungen gegen Ego-Impulse\",\n            \"Kreativer Ausdruck als gelebte Seelensprache\"\n        ],\n        dissonance: [\n            \"Dauerhafte Bet\\xe4ubung durch Reize und Konsum\",\n            \"Zynismus, Groll und Verh\\xe4rtung\",\n            \"Ignorierte Intuition und verdr\\xe4ngte Symbolik\",\n            \"Anhaftung an Trennung statt Einheitsbewusstsein\"\n        ]\n    }\n];\nconst naturalCausalityText = \"Resonanz und Dissonanz sind keine moralischen Kategorien und keine S\\xfcndenlehre. Sie beschreiben nat\\xfcrliche Kausalit\\xe4t im Energiemanagement: Was Klarheit, Integrit\\xe4t und Pr\\xe4senz st\\xe4rkt, erh\\xf6ht Resonanz. Was bet\\xe4ubt, fragmentiert oder bindet, erzeugt Dissonanz.\";\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./lib/path-of-practice.ts\n");

