"use strict";
eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   principlesEn: () => (/* binding */ principlesEn)\n/* harmony export */ });\nconst principlesEn = {\n    1: {\n        title: \"Immortal Soul\",\n        statement: \"I recognize that I am an immortal soul having a human experience.\",\n        detail: \"I am not my body. I am not my name, my story, or my role. I am a soul - a being of light and energy clothed in a human body for this incarnation. This body is my instrument, not my essence. This is not merely an idea; it is the foundation everything else rests on. Whenever I forget who I am, I return to this truth.\"\n    },\n    2: {\n        title: \"Responsibility\",\n        statement: \"I take responsibility for my life as a consciously chosen learning journey.\",\n        detail: \"My life is not random. It is not punishment. It is not a blind twist of fate. Before incarnation, I consciously chose this life with its gifts, challenges, people, and turning points. That does not mean it is easy; it means it is meaningful. Therefore I seek responsibility first within myself, not first outside.\"\n    },\n    3: {\n        title: \"Soul Knowing\",\n        statement: \"I trust the inner knowing of my soul beyond the ego.\",\n        detail: \"My ego is loud. It judges, compares, doubts, and craves. My soul is quiet. It knows - often through subtle feelings, impulses, and calm certainties. I learn to distinguish both voices. When they conflict, I practice trusting the soul, even when ego protests.\"\n    },\n    4: {\n        title: \"Self-Observation\",\n        statement: \"I practice self-observation without self-condemnation.\",\n        detail: \"I look honestly at my patterns, weaknesses, and mistakes - not to punish myself, but to understand myself. Observation without compassion becomes self-violence. Compassion without observation becomes self-deception. I need both: clear sight and a warm heart. I am a soul in a human learning process; mistakes are part of growth.\"\n    },\n    5: {\n        title: \"Sacred Context\",\n        statement: \"I accept body, family, and life circumstances as a meaningful container for my soul path.\",\n        detail: \"This body, with its strengths and limits. This family, with its love and wounds. This time, place, and context. None of it is arbitrary. These conditions hold exactly the curriculum my soul needs in this incarnation. Acceptance does not mean approval of everything; it means stopping the war against reality and asking: what is mine to learn here?\"\n    },\n    6: {\n        title: \"Guidance\",\n        statement: \"I maintain connection to my guides and higher soul.\",\n        detail: \"I am not alone and never have been. Every soul has companions on the other side - guides who support lovingly without violating free will. My higher soul carries the broader memory of the journey. Through silence, meditation, prayer, and willingness to listen, this connection becomes tangible.\"\n    },\n    7: {\n        title: \"Past-Life Wisdom\",\n        statement: \"I honor the wisdom of past lives as part of my growth path.\",\n        detail: \"I am older than this single life. I have lived in other contexts, roles, and conditions. Deep talents, irrational fears, and immediate resonance with people or places can carry memory traces from former lives. I meet these patterns with curiosity instead of rejection.\"\n    },\n    8: {\n        title: \"Incarnation Design\",\n        statement: \"I trust that my life was meaningfully designed before incarnation.\",\n        detail: \"Before entering this body, I co-designed a life plan with guides and soul companions. Not every detail was fixed - free will remains sacred - yet core themes, pivotal encounters, and major lessons were intentionally set. In confusion I remember: there is a wider context my human mind may not fully see.\"\n    },\n    9: {\n        title: \"Soul Home\",\n        statement: \"I recognize the soul world as my deeper home and earthly life as a conscious stay.\",\n        detail: \"Life between lives is not annihilation; it is home. Incarnation is the visit. I live here fully engaged while remembering I belong to a greater continuity. This perspective softens fear of death, releases compulsive seriousness, and reframes suffering.\"\n    },\n    10: {\n        title: \"Cosmic Order\",\n        statement: \"I acknowledge the cosmic order of higher beings and place myself trustfully within it.\",\n        detail: \"There is an order beyond my current understanding. Traditions and regressions describe highly mature intelligences guiding soul evolution. I do not need total comprehension to live in trust. I can surrender control without surrendering responsibility.\"\n    },\n    11: {\n        title: \"Soul Companions\",\n        statement: \"I recognize that I evolve with specific souls across many lives.\",\n        detail: \"Some encounters carry instant recognition: 'I know you.' This depth is often memory, not coincidence. Soul groups reappear across incarnations in changing roles - parent, partner, child, ally, challenger. These beings are core companions in my long development.\"\n    },\n    12: {\n        title: \"Difficult Bonds\",\n        statement: \"I meet soul siblings with special care, even when encounters are difficult.\",\n        detail: \"Not all soul companions appear as comfort. Some arrive as friction, conflict, or pain. This is not necessarily error; it can be a conscious agreement serving growth. I hold even difficult encounters with the possibility of deeper meaning.\"\n    },\n    13: {\n        title: \"Relational Lessons\",\n        statement: \"I understand that my closest relationships often hold the deepest lessons.\",\n        detail: \"My most intimate bonds are rarely random. They carry concentrated agreements for development. Therefore close relationships can also be the most demanding. I do not treat them as burden alone; I recognize them as primary classrooms of the soul.\"\n    },\n    14: {\n        title: \"Group Evolution\",\n        statement: \"I contribute consciously to the evolution of my soul group.\",\n        detail: \"My growth is not merely personal. As I resolve a lesson, I lighten the shared field of my soul group. We are developmentally interwoven. I carry this responsibility consciously: my maturation serves more than myself.\"\n    },\n    15: {\n        title: \"Life Review\",\n        statement: \"I see life review not as judgment but as loving learning, in death and in life.\",\n        detail: \"Life review is described as complete, honest, and compassionate seeing - not condemnation. One perceives not only personal action, but also its impact on others. No external judge is required; truth itself teaches. I practice this now through regular, courageous, compassionate reflection.\"\n    },\n    16: {\n        title: \"Specialization\",\n        statement: \"I recognize that my soul carries maturity and specialization calling me to specific contributions.\",\n        detail: \"Across many incarnations, souls do not only mature generally; they also specialize. Certain gifts, capacities, and service lines become clearer over time. I listen for this call and move toward it, even when the path appears uncertain.\"\n    },\n    17: {\n        title: \"Energy Hygiene\",\n        statement: \"I care for the natural energy of my soul in everyday life.\",\n        detail: \"Soul energy can clarify or cloud depending on inner condition and conduct. What clouds it: resentment, addiction, avoidance, dishonesty, unresolved conflict. What clarifies it: forgiveness, silence, integrity, service, and love. I treat this as practical hygiene, not abstraction.\"\n    },\n    18: {\n        title: \"Chosen Incarnation\",\n        statement: \"I know each incarnation was consciously chosen and I live accordingly.\",\n        detail: \"This life was not accidentally assigned; it was consciously embraced. That insight is not an excuse for passivity. It is an invitation to full authorship: present, courageous, and accountable engagement with the life I came to live.\"\n    },\n    19: {\n        title: \"Lesson in Challenge\",\n        statement: \"I meet challenges as consciously chosen soul lessons.\",\n        detail: \"When pain, loss, or rupture appears, I do not ask only 'Why me?' I also ask 'What is this inviting me to learn?' This is not denial of suffering. It is a deeper orientation to meaning that keeps transformation possible.\"\n    },\n    20: {\n        title: \"Compassion\",\n        statement: \"I cultivate compassion-first for myself, then for all others.\",\n        detail: \"Compassion starts within. Without inner kindness, outward care collapses into duty, projection, or exhaustion. I speak to myself with truthful warmth. From that internal ground, authentic compassion can extend naturally to others.\"\n    },\n    21: {\n        title: \"Transmutation\",\n        statement: \"I transform fear, judgment, and ego into understanding and love.\",\n        detail: \"Fear is ego's default contraction; judgment is often fear projected outward. I do not attempt to crush these states, because repression strengthens them. I meet them consciously, understand their roots, and transmute them through clarity, humility, and compassion.\"\n    },\n    22: {\n        title: \"Karmic Resolution\",\n        statement: \"I resolve unresolved patterns and karma actively, not through avoidance.\",\n        detail: \"Karma is not punishment; it is unfinished energy seeking completion. It appears as repetition loops in relationships, behavior, conflict, and even physiology. I do not bypass these loops. I move through them consciously, with support when needed, until integration occurs.\"\n    },\n    23: {\n        title: \"Integrity\",\n        statement: \"I act with integrity, because every action shapes my soul character.\",\n        detail: \"Integrity means my actions align with my values even when unseen or inconvenient. Small compromises accumulate just as small acts of truth accumulate. Every act leaves an energetic signature. I choose alignment in the small moments where character is actually formed.\"\n    },\n    24: {\n        title: \"Joy and Lightness\",\n        statement: \"I cultivate joy and lightness as true expressions of soul, not distraction.\",\n        detail: \"Soul maturity is not grim rigidity. As fear and ego contraction soften, natural joy returns. I cultivate play, laughter, and simple delight as spiritual qualities - not escapism. Lightness can be depth in motion.\"\n    },\n    25: {\n        title: \"Inner Language\",\n        statement: \"I learn the language of my soul: symbols, dreams, intuition, and inner imagery.\",\n        detail: \"The soul often communicates non-verbally: symbols, synchronicities, felt knowing, dream motifs. This language is subtle and precise, and it can be learned. I document signals, sit with them, and let meaning emerge before forcing premature interpretation.\"\n    },\n    26: {\n        title: \"Silence\",\n        statement: \"I create silence so the quiet voice of the soul can be heard.\",\n        detail: \"The soul whispers while the ego shouts. In a world of constant stimulation, silence becomes a radical discipline. I create intentional intervals without noise, scrolling, or distraction. In that space, deeper guidance becomes audible.\"\n    },\n    27: {\n        title: \"Intuition\",\n        statement: \"I trust intuition as a direct expression of soul knowledge.\",\n        detail: \"Authentic intuition is neither panic nor fantasy. It is a calm, clear signal arising beneath reactive mind states. I practice distinguishing this signal from fear and desire, then act with increasing trust in that deeper intelligence.\"\n    },\n    28: {\n        title: \"Soul in Everyone\",\n        statement: \"I recognize every human being as a soul on their own developmental path.\",\n        detail: \"Every person I meet is a soul in process - including those I resist or misunderstand. This recognition does not erase boundaries, but it transforms perception. Speech softens, judgment loosens, and interaction becomes more conscious.\"\n    },\n    29: {\n        title: \"Service from Fullness\",\n        statement: \"I serve others not from duty, but from genuine compassion.\",\n        detail: \"Service born from pressure depletes. Service born from connectedness nourishes. I do not help to appear virtuous or avoid guilt; I help from sincere recognition of shared being. Sustainable service requires an inner vessel that is actually resourced.\"\n    },\n    30: {\n        title: \"Free Will\",\n        statement: \"I respect each soul's free will so deeply that I do not force help where none is asked.\",\n        detail: \"This is one of the hardest disciplines. Even with good intent, unsolicited rescue can violate growth timing. I offer presence, clarity, and support - without coercion. I remain available, but I do not impose.\"\n    },\n    31: {\n        title: \"Collective Field\",\n        statement: \"I consciously contribute to the evolution of collective consciousness.\",\n        detail: \"Inner work is never merely private. Every step toward clarity, integrity, and compassion influences relational and collective fields. I am a node in a larger network. My inner quality is a civilizational contribution.\"\n    },\n    32: {\n        title: \"Embodied Example\",\n        statement: \"I live as an example that soul mastery is possible in daily life.\",\n        detail: \"I do not rely on preaching or pressure. I let lived coherence speak first. When people ask, I share openly; until then, embodiment remains the primary message. A life aligned with soul is itself instruction.\"\n    },\n    33: {\n        title: \"Civilizational Vision\",\n        statement: \"I hold the vision of a civilization grounded in soul growth.\",\n        detail: \"I hold a vision larger than personal success: a humanity reorganized around consciousness, truth, and compassion rather than control and extraction. This vision is not naive idealism; it is directional intelligence. I sustain it as orientation, prayer, and practice.\"\n    },\n    34: {\n        title: \"Unity\",\n        statement: \"I recognize all souls arise from one universal source and return to unity each day.\",\n        detail: \"At depth, all souls share one origin and one belonging. Separation is real as an experience, but not ultimate as essence. Through meditation, relationship, and awe, I practice returning to this unity daily.\"\n    },\n    35: {\n        title: \"Living Truth\",\n        statement: \"I keep my worldview alive - trusting present knowledge while remaining open to deeper truth.\",\n        detail: \"I treat current insight as valuable but not final. I stay open to new evidence, experience, and correction without collapsing into relativism. What proves true is retained; what is outgrown is released. My foundation is not rigid doctrine, but devotion to truth itself.\"\n    }\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./lib/principles-en.ts\n");

