eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   principles: () => (/* binding */ principles),\n/* harmony export */   spheres: () => (/* binding */ spheres)\n/* harmony export */ });\nconst spheres = [\n    \"Innere Ordnung\",\n    \"Die Seelenwelt\",\n    \"Die Seelengruppe\",\n    \"Charakter-Alchemie\",\n    \"Die neue Zivilisation\"\n];\nconst principles = [\n    {\n        id: 1,\n        sphere: \"Innere Ordnung\",\n        title: \"Unsterbliche Seele\",\n        statement: \"Ich erkenne, dass ich eine unsterbliche Seele bin, die eine menschliche Erfahrung macht.\",\n        detail: \"Ich bin nicht mein K\\xf6rper. Ich bin nicht mein Name, meine Geschichte, meine Rolle. Ich bin eine Seele — ein Wesen aus Licht und Energie, das sich f\\xfcr diese Inkarnation in einen menschlichen K\\xf6rper eingekleidet hat. Dieser K\\xf6rper ist mein Werkzeug, nicht mein Wesen. Diese Erkenntnis ist nicht nur ein Gedanke — sie ist die Grundlage, auf der alles andere ruht. Wenn ich vergesse, wer ich bin, kehre ich zu dieser Wahrheit zur\\xfcck.\"\n    },\n    {\n        id: 2,\n        sphere: \"Innere Ordnung\",\n        title: \"Verantwortung\",\n        statement: \"Ich nehme Verantwortung f\\xfcr mein Leben als bewusst gew\\xe4hlte Lernreise.\",\n        detail: \"Mein Leben ist kein Zufall. Es ist keine Strafe. Es ist keine blinde Laune des Schicksals. Ich habe dieses Leben — mit all seinen Schwierigkeiten, seinen Gaben, seinen Menschen und seinen Wendungen — vor meiner Inkarnation bewusst gew\\xe4hlt. Das bedeutet nicht, dass alles leicht ist. Es bedeutet, dass alles einen Sinn hat. Und es bedeutet, dass ich die Verantwortung f\\xfcr mein Leben bei mir selbst suche — nicht zuerst au\\xdfen.\"\n    },\n    {\n        id: 3,\n        sphere: \"Innere Ordnung\",\n        title: \"Seelenwissen\",\n        statement: \"Ich vertraue dem inneren Wissen meiner Seele \\xfcber das Ego hinaus.\",\n        detail: \"Mein Ego ist laut. Es urteilt, vergleicht, zweifelt, begehrt. Meine Seele ist leise. Sie wei\\xdf. Nicht immer in Worten — oft in Gef\\xfchlen, Impulsen, stillen Gewissheiten, die nicht zu erkl\\xe4ren sind, aber sich tief richtig anf\\xfchlen. Ich lerne, diese beiden Stimmen zu unterscheiden. Und wenn sie in Konflikt stehen, \\xfcbe ich, der Seele zu vertrauen — auch wenn das Ego protestiert.\"\n    },\n    {\n        id: 4,\n        sphere: \"Innere Ordnung\",\n        title: \"Selbstbeobachtung\",\n        statement: \"Ich \\xfcbe den Weg der Selbstbeobachtung ohne Selbstverurteilung.\",\n        detail: \"Ich schaue ehrlich auf mich selbst. Ich sehe meine Muster, meine Schw\\xe4chen, meine Fehler — nicht um mich zu bestrafen, sondern um mich zu verstehen. Selbstbeobachtung ohne Mitgef\\xfchl wird zur Selbstfolter. Mitgef\\xfchl ohne Selbstbeobachtung wird zur Selbstt\\xe4uschung. Ich brauche beides: den klaren Blick und das warme Herz. Ich bin eine Seele in einem menschlichen K\\xf6rper — Fehler sind Teil des Lernens, nicht Beweise meines Versagens.\"\n    },\n    {\n        id: 5,\n        sphere: \"Innere Ordnung\",\n        title: \"Annahme der H\\xfclle\",\n        statement: \"Ich nehme den K\\xf6rper, die Familie und die Lebensumst\\xe4nde, die ich gew\\xe4hlt habe, als sinnvolle H\\xfclle meiner Seelenreise an.\",\n        detail: \"Dieser K\\xf6rper — mit seinen St\\xe4rken und Grenzen. Diese Familie — mit ihrer Liebe und ihren Wunden. Dieses Land, diese Zeit, diese Umst\\xe4nde. Ich habe sie gew\\xe4hlt. Nicht willk\\xfcrlich, sondern weil sie genau das Lernfeld enthalten, das meine Seele in dieser Inkarnation braucht. Annahme bedeutet nicht, alles gutzuhei\\xdfen. Sie bedeutet, aufzuh\\xf6ren, gegen die Grundbedingungen meines Lebens zu k\\xe4mpfen — und stattdessen zu fragen: Was will ich hier lernen?\"\n    },\n    {\n        id: 6,\n        sphere: \"Die Seelenwelt\",\n        title: \"Geistf\\xfchrer\",\n        statement: \"Ich halte die Verbindung zu meinen Geistf\\xfchrern und meiner h\\xf6heren Seele aufrecht.\",\n        detail: \"Ich bin nicht allein. Ich war nie allein. Jede Seele hat Begleiter auf der anderen Seite — Geistf\\xfchrer, die ihren Weg kennen, die sie liebevoll begleiten und die nie eingreifen, ohne gefragt zu werden. Meine h\\xf6here Seele — der Teil von mir, der nicht vollst\\xe4ndig inkarniert ist — tr\\xe4gt das Wissen des gesamten Weges. Ich pflege diese Verbindung durch Stille, Meditation, Gebet und die Bereitschaft zuzuh\\xf6ren.\"\n    },\n    {\n        id: 7,\n        sphere: \"Die Seelenwelt\",\n        title: \"Vergangene Leben\",\n        statement: \"Ich erkenne die Weisheit vergangener Leben als Teil meines Wachstumspfades.\",\n        detail: \"Ich bin \\xe4lter als dieses Leben. Ich habe bereits gelebt — als Mann und als Frau, als Arm und als Reich, in Kulturen und Zeiten, die sich von dieser fundamental unterscheiden. Die Muster, die mich in diesem Leben pr\\xe4gen — tiefe Talente, unerkl\\xe4rliche \\xc4ngste, sofortige Verbindungen zu bestimmten Menschen oder Orten — tragen oft die Erinnerung vergangener Leben in sich. Ich begegne diesen Mustern mit Neugier statt mit Ablehnung.\"\n    },\n    {\n        id: 8,\n        sphere: \"Die Seelenwelt\",\n        title: \"Inkarnationsplan\",\n        statement: \"Ich vertraue darauf, dass mein Leben vor der Inkarnation sinnvoll geplant wurde.\",\n        detail: \"Bevor ich in diesen K\\xf6rper eintrat, habe ich gemeinsam mit meinen Geistf\\xfchrern und meiner Seelengruppe einen Plan f\\xfcr dieses Leben entworfen. Nicht jeden Detail — der freie Wille bleibt heilig. Aber die gro\\xdfen Themen, die zentralen Begegnungen, die wesentlichen Lektionen — sie wurden bewusst gesetzt. Wenn das Leben mich vor Herausforderungen stellt, die ich nicht verstehe, erinnere ich mich: Es gibt einen gr\\xf6\\xdferen Zusammenhang, den mein menschlicher Geist vielleicht nicht vollst\\xe4ndig sieht.\"\n    },\n    {\n        id: 9,\n        sphere: \"Die Seelenwelt\",\n        title: \"Zwischenwelt\",\n        statement: \"Ich anerkenne die Zwischenwelt als eigentliche Heimat meiner Seele — das irdische Leben als bewusst gew\\xe4hlten Aufenthalt.\",\n        detail: \"Das Leben zwischen den Leben ist nicht der Tod — es ist das Zuhause. Die Inkarnation ist der Aufenthalt. Ich lebe in diesem K\\xf6rper wie ein Reisender in einem fremden Land — vollst\\xe4ndig pr\\xe4sent, vollst\\xe4ndig engagiert, und gleichzeitig wissend, dass ich eine Heimat habe, zu der ich zur\\xfcckkehren werde. Diese Perspektive ver\\xe4ndert alles: Sie nimmt dem Tod seinen Schrecken, dem Leben seinen krampfhaften Ernst und dem Leid seine absolute Endg\\xfcltigkeit.\"\n    },\n    {\n        id: 10,\n        sphere: \"Die Seelenwelt\",\n        title: \"Kosmische Ordnung\",\n        statement: \"Ich erkenne die kosmische Ordnung h\\xf6herer Wesenheiten an und bette mich vertrauensvoll in sie ein.\",\n        detail: \"Es gibt eine Ordnung jenseits meines Verstehens. Newton beschreibt einen Rat h\\xf6herer Wesenheiten — Seelen von au\\xdferordentlicher Reife und Weisheit, die den Inkarnationsprozess begleiten und die Entwicklung der Seelen f\\xfchren. Ich muss diese Ordnung nicht vollst\\xe4ndig verstehen, um ihr zu vertrauen. Wie ein Kind, das nicht alle Entscheidungen seiner Eltern begreift und ihnen dennoch grundlegend vertrauen kann — so bette ich mich in die kosmische Ordnung ein, ohne sie kontrollieren zu m\\xfcssen.\"\n    },\n    {\n        id: 11,\n        sphere: \"Die Seelengruppe\",\n        title: \"Weggef\\xe4hrten\",\n        statement: \"Ich erkenne, dass ich mit bestimmten Seelen durch viele Leben gemeinsam wachse.\",\n        detail: \"Es gibt Menschen in meinem Leben, bei denen ich sofort das Gef\\xfchl habe: Ich kenne dich. Diese tiefe Vertrautheit ist kein Zufall — sie ist Erinnerung. Meine Seelengruppe ist der Kreis von Seelen, mit denen ich immer wieder inkarniere, in wechselnden Rollen: heute mein Vater, in einem anderen Leben mein Freund, in einem weiteren mein Kind. Diese Seelen sind meine tiefsten Weggef\\xe4hrten — und ich bin es f\\xfcr sie.\"\n    },\n    {\n        id: 12,\n        sphere: \"Die Seelengruppe\",\n        title: \"Achtsamkeit in Reibung\",\n        statement: \"Ich begegne meinen Seelengeschwistern mit besonderer Achtsamkeit — auch wenn die Begegnung schwierig ist.\",\n        detail: \"Nicht alle Seelengeschwister begegnen mir als Freunde. Manche kommen als Herausforderung — als Konflikt, als Schmerz, als tiefe Reibung. Das ist kein Zufall und kein Fehler. Es ist ein bewusstes Arrangement: Diese Seele hat sich bereit erkl\\xe4rt, mir eine schwierige Lektion zu geben — aus Liebe, nicht aus Feindschaft. Ich begegne auch schwierigen Menschen mit dieser M\\xf6glichkeit im Hinterkopf.\"\n    },\n    {\n        id: 13,\n        sphere: \"Die Seelengruppe\",\n        title: \"Beziehungslektionen\",\n        statement: \"Ich verstehe, dass meine engsten Beziehungen oft die tiefsten Seelenlektionen tragen.\",\n        detail: \"Mein Partner, meine Kinder, meine Eltern, meine engsten Freunde — sie sind nicht zuf\\xe4llig in meinem Leben. Sie sind die Menschen, mit denen ich die intensivsten Lektionen vereinbart habe. Deshalb sind die engsten Beziehungen oft die schwierigsten. Deshalb treffen sie am tiefsten. Deshalb fordern sie am meisten. Ich begegne diesen Beziehungen nicht als B\\xfcrde, sondern als die wichtigsten Lernr\\xe4ume meines Lebens.\"\n    },\n    {\n        id: 14,\n        sphere: \"Die Seelengruppe\",\n        title: \"Gruppenentwicklung\",\n        statement: \"Ich trage bewusst zur Entwicklung unserer gemeinsamen Seelengruppe bei.\",\n        detail: \"Mein Wachstum ist nicht nur meins. Wenn ich mich entwickle, entwickle ich mich auch im Namen meiner Seelengruppe — denn wir sind miteinander verwoben. Wenn ich eine Lektion lerne, die wir gemeinsam als Gruppe vereinbart haben, entlaste ich auch die anderen. Ich trage diese Verantwortung bewusst: Meine Seelenmeisterschaft ist ein Geschenk nicht nur an mich, sondern an alle, mit denen ich durch die Zeiten reise.\"\n    },\n    {\n        id: 15,\n        sphere: \"Charakter-Alchemie\",\n        title: \"Life Review\",\n        statement: \"Ich nehme die \\xdcberpr\\xfcfung meines Lebens nicht als Gericht, sondern als liebevolles Lernen wahr — im Tod wie im Leben.\",\n        detail: \"Nach dem Tod durchl\\xe4uft jede Seele einen Life Review — eine vollst\\xe4ndige, ungesch\\xf6nte Betrachtung des gelebten Lebens. Newton beschreibt diesen Prozess nicht als Strafe, sondern als tiefes Lernen: Man erlebt nicht nur die eigenen Handlungen, sondern auch ihre Wirkung auf andere — von innen. Kein Richter urteilt. Die Seele selbst versteht. Ich praktiziere diesen Life Review bereits im Leben: regelm\\xe4\\xdfige, ehrliche, mitf\\xfchlende Selbstbetrachtung — nicht um zu verurteilen, sondern um zu verstehen.\"\n    },\n    {\n        id: 16,\n        sphere: \"Charakter-Alchemie\",\n        title: \"Seelenspezialisierung\",\n        statement: \"Ich erkenne, dass meine Seele eine Reife und eine Spezialisierung tr\\xe4gt, die mich zu bestimmten Beitr\\xe4gen beruft.\",\n        detail: \"Seelen entwickeln im Laufe vieler Inkarnationen nicht nur allgemeine Reife — sie entwickeln auch Spezialisierungen: bestimmte Talente, F\\xe4higkeiten und Rollen, die sie besonders gut erf\\xfcllen k\\xf6nnen. Heiler, Lehrer, H\\xfcter, Sch\\xf6pfer, Krieger des Lichts. Ich sp\\xfcre in mir, wozu meine Seele berufen ist — und ich verfolge diesen Ruf, auch wenn der Weg ungewiss erscheint.\"\n    },\n    {\n        id: 17,\n        sphere: \"Charakter-Alchemie\",\n        title: \"Energiehygiene\",\n        statement: \"Ich achte auf die nat\\xfcrliche Energie meiner Seele und pflege sie bewusst im Alltag.\",\n        detail: \"Newton beschreibt Seelenenergie als reales Ph\\xe4nomen — als Licht, das klarer oder tr\\xfcber sein kann, je nach Entwicklungsstand und innerem Zustand. Was tr\\xfcbt meine Energie? Ungel\\xf6ste Konflikte, Ressentiments, Angst, Sucht, Unehrlichkeit. Was kl\\xe4rt sie? Vergebung, Stille, Liebe, Integrit\\xe4t, Dienst. Ich beobachte meinen energetischen Zustand und pflege ihn aktiv — nicht als esoterisches Konzept, sondern als praktische t\\xe4gliche Hygiene.\"\n    },\n    {\n        id: 18,\n        sphere: \"Charakter-Alchemie\",\n        title: \"Bewusste Inkarnation\",\n        statement: \"Ich wei\\xdf, dass jede Inkarnation eine bewusste Wahl war — und lebe sie entsprechend.\",\n        detail: \"Ich habe dieses Leben nicht zuf\\xe4llig bekommen. Ich habe es gew\\xe4hlt — mit dem Wissen, was es bringen w\\xfcrde, und dem Willen, daran zu wachsen. Diese Erkenntnis ist keine Entschuldigung f\\xfcr Passivit\\xe4t — sie ist eine Einladung zur vollen \\xdcbernahme meines Lebens. Ich lebe diese Inkarnation so vollst\\xe4ndig wie m\\xf6glich: pr\\xe4sent, mutig, offen, engagiert.\"\n    },\n    {\n        id: 19,\n        sphere: \"Charakter-Alchemie\",\n        title: \"Lektion im Schmerz\",\n        statement: \"Ich begegne Herausforderungen als bewusst gew\\xe4hlte Lektionen meiner Seele.\",\n        detail: \"Wenn das Leben mich bricht, wenn Schmerz kommt, wenn Verlust mich trifft — ich frage nicht zuerst: Warum passiert mir das? Ich frage: Was will ich hier lernen? Das ist keine naive Sch\\xf6nf\\xe4rberei. Es ist die tiefste verf\\xfcgbare Perspektive auf menschliches Leid. Nicht jeder Schmerz muss sofort verstanden werden. Aber jeder Schmerz tr\\xe4gt die M\\xf6glichkeit einer Lektion in sich — und ich bleibe offen f\\xfcr sie.\"\n    },\n    {\n        id: 20,\n        sphere: \"Charakter-Alchemie\",\n        title: \"Mitgef\\xfchl\",\n        statement: \"Ich kultiviere Mitgef\\xfchl — zuerst f\\xfcr mich selbst, dann f\\xfcr alle anderen.\",\n        detail: \"Mitgef\\xfchl beginnt innen. Wer sich selbst nicht mit Mitgef\\xfchl begegnet, kann anderen kein echtes Mitgef\\xfchl schenken — nur Pflicht, Mitleid oder Projektion. Ich \\xfcbe, mit mir selbst so zu sprechen, wie ich mit einem guten Freund sprechen w\\xfcrde: ehrlich, aber warm. Klar, aber liebevoll. Von diesem inneren Fundament aus w\\xe4chst echtes Mitgef\\xfchl f\\xfcr andere — nicht als Aufopferung, sondern als nat\\xfcrlicher Ausdruck von F\\xfclle.\"\n    },\n    {\n        id: 21,\n        sphere: \"Charakter-Alchemie\",\n        title: \"Transformation\",\n        statement: \"Ich transformiere Angst, Urteil und Ego in Verst\\xe4ndnis und Liebe.\",\n        detail: \"Angst ist der h\\xe4ufigste Zustand des Egos. Urteil ist Angst, die nach au\\xdfen projiziert wird. Ego ist die Illusion, getrennt und allein zu sein. Ich bek\\xe4mpfe diese Zust\\xe4nde nicht — Bek\\xe4mpfung st\\xe4rkt sie. Ich transformiere sie: indem ich die Angst anschaue, ihre Wurzel verstehe und ihr mit Mitgef\\xfchl begegne. Indem ich das Urteil \\xfcber andere als Spiegel meiner eigenen ungel\\xf6sten Themen erkenne. Indem ich das Ego als n\\xfctzliches Werkzeug f\\xfchre, statt von ihm gef\\xfchrt zu werden.\"\n    },\n    {\n        id: 22,\n        sphere: \"Charakter-Alchemie\",\n        title: \"Karma-Aufl\\xf6sung\",\n        statement: \"Ich l\\xf6se ungel\\xf6ste Muster und Karma aktiv auf — nicht durch Vermeidung, sondern durch bewusstes Durchleben.\",\n        detail: \"Karma ist keine Strafe — es ist ungel\\xf6ste Energie, die nach Abschluss sucht. Diese Energie zeigt sich als Wiederholungsmuster: in Beziehungen, in Konflikten, in Selbstsabotage, in k\\xf6rperlichen Beschwerden. Ich umgehe diese Muster nicht — ich gehe hindurch. Bewusst, mutig, mit Unterst\\xfctzung wo n\\xf6tig. Jedes Muster, das ich aufl\\xf6se, reinigt meine Seelenenergie und befreit mich f\\xfcr den n\\xe4chsten Schritt.\"\n    },\n    {\n        id: 23,\n        sphere: \"Charakter-Alchemie\",\n        title: \"Integrit\\xe4t\",\n        statement: \"Ich handele mit Integrit\\xe4t, denn jede Handlung formt meinen Seelencharakter.\",\n        detail: \"Integrit\\xe4t bedeutet: Meine Handlungen stimmen mit meinen Werten \\xfcberein — auch wenn niemand zuschaut. Auch wenn es unbequem ist. Auch wenn die L\\xfcge einfacher w\\xe4re. Jede Handlung hinterl\\xe4sst eine energetische Signatur in meiner Seele. Kleine Unehrlichkeiten summieren sich genauso wie kleine Akte der Integrit\\xe4t. Ich entscheide mich t\\xe4glich — in kleinen Momenten — f\\xfcr den Weg der Seele.\"\n    },\n    {\n        id: 24,\n        sphere: \"Charakter-Alchemie\",\n        title: \"Freude & Leichtigkeit\",\n        statement: \"Ich kultiviere Freude und Leichtigkeit als echten Ausdruck meiner Seele — nicht als Ablenkung, sondern als spirituellen Zustand.\",\n        detail: \"Seelenmeisterschaft ist kein ernstes, graues Unterfangen. Newton beschreibt die Zwischenwelt als Ort tiefer Freude, Humor und Leichtigkeit — das ist der nat\\xfcrliche Zustand der Seele. Je mehr ich mich von Ego, Angst und Anhaftung befreie, desto mehr kehrt diese nat\\xfcrliche Freude zur\\xfcck. Ich kultiviere sie aktiv: durch Spiel, durch Lachen, durch Genuss der einfachen Dinge — als spirituelle Praxis, nicht als Flucht.\"\n    },\n    {\n        id: 25,\n        sphere: \"Charakter-Alchemie\",\n        title: \"Innere Sprache\",\n        statement: \"Ich lerne die Sprache meiner Seele: Symbole, Tr\\xe4ume, Intuition und innere Bilder.\",\n        detail: \"Die Seele spricht nicht in Worten. Sie spricht in Bildern, Gef\\xfchlen, Tr\\xe4umen, Synchronizit\\xe4ten — in der pl\\xf6tzlichen Gewissheit, die keiner Erkl\\xe4rung bedarf. Diese Sprache ist real. Sie ist pr\\xe4zise. Aber sie muss gelernt werden — wie jede andere Sprache. Ich nehme mir Zeit, die Signale meiner Seele zu bemerken, aufzuzeichnen und zu verstehen. Ein Traumtagebuch, ein Symboljournal, stille Reflexion nach bedeutsamen Erlebnissen.\"\n    },\n    {\n        id: 26,\n        sphere: \"Charakter-Alchemie\",\n        title: \"Macht der Stille\",\n        statement: \"Ich schaffe Stille, damit die leise Stimme der Seele geh\\xf6rt werden kann.\",\n        detail: \"Die Seele fl\\xfcstert. Das Ego schreit. In einer Welt voller L\\xe4rm, Ablenkung und konstanter Stimulation ist Stille eine radikale Praxis. Ich schaffe sie t\\xe4glich — nicht nur in der formalen Meditation, sondern in bewussten Momenten der Unterbrechung: kein Telefon, keine Musik, keine Ablenkung. Nur ich und das, was in mir ist. In dieser Stille beginnt die Seele zu sprechen.\"\n    },\n    {\n        id: 27,\n        sphere: \"Charakter-Alchemie\",\n        title: \"Intuition\",\n        statement: \"Ich vertraue meiner Intuition als direktem Ausdruck meines Seelenwissens.\",\n        detail: \"Intuition ist kein irrationales Bauchgef\\xfchl — sie ist das Wissen der Seele, das durch den K\\xf6rper spricht. Wenn ich eine tiefe, ruhige Gewissheit sp\\xfcre — jenseits von Wunschdenken, jenseits von Angst — dann ist das die Stimme meiner Seele. Ich lerne, sie von den Stimmen des Egos zu unterscheiden. Und ich lerne, ihr zu vertrauen — auch wenn der Verstand Einw\\xe4nde hat.\"\n    },\n    {\n        id: 28,\n        sphere: \"Die neue Zivilisation\",\n        title: \"Seele in jedem\",\n        statement: \"Ich erkenne in jedem Menschen eine Seele auf ihrem eigenen Entwicklungsweg.\",\n        detail: \"Jeder Mensch, dem ich begegne — der Obdachlose auf der Stra\\xdfe, der aggressive Fremde, der schwierige Kollege, das weinende Kind — ist eine Seele. Eine unsterbliche, ewige Seele, die gerade eine menschliche Erfahrung macht. Diese Seele ist nicht weniger wert als meine. Sie ist nicht weiter von der Quelle entfernt als ich. Sie befindet sich an einem anderen Punkt ihrer Reise — das ist alles. Diese Erkenntnis ver\\xe4ndert jeden Blick, jeden Satz, jede Begegnung.\"\n    },\n    {\n        id: 29,\n        sphere: \"Die neue Zivilisation\",\n        title: \"Dienst aus F\\xfclle\",\n        statement: \"Ich diene anderen nicht aus Pflicht, sondern aus aufrichtigem Mitgef\\xfchl.\",\n        detail: \"Dienst, der aus Pflicht entsteht, ersch\\xf6pft. Dienst, der aus Mitgef\\xfchl entsteht, n\\xe4hrt. Ich helfe nicht, um gut dazustehen, um Schuld zu vermeiden oder um Anerkennung zu erhalten. Ich helfe, weil ich verstanden habe, dass wir alle verbunden sind — und dass das Wohl des anderen mein Wohl ist. Dieser Dienst setzt voraus, dass mein eigenes Gef\\xe4\\xdf voll ist. Ich kann nicht aus dem Leeren schenken.\"\n    },\n    {\n        id: 30,\n        sphere: \"Die neue Zivilisation\",\n        title: \"Freier Wille\",\n        statement: \"Ich respektiere den freien Willen jeder Seele so tief, dass ich nicht helfe, wo keine Hilfe gefragt ist — auch wenn es schwer f\\xe4llt.\",\n        detail: \"Das ist eines der schwierigsten Gebote. Ich sehe einen Menschen leiden und m\\xf6chte eingreifen. Ich sehe einen Fehler und m\\xf6chte korrigieren. Ich sehe einen Weg und m\\xf6chte ihn zeigen. Aber jede Seele hat das Recht, ihren eigenen Weg zu gehen — auch wenn dieser Weg durch Schmerz f\\xfchrt. Newton beschreibt, dass selbst Geistf\\xfchrer nicht eingreifen, ohne gefragt zu werden. Ich respektiere dieses Prinzip: Ich biete an, ich \\xf6ffne mich, ich bin verf\\xfcgbar — aber ich dr\\xe4nge mich nicht auf.\"\n    },\n    {\n        id: 31,\n        sphere: \"Die neue Zivilisation\",\n        title: \"Kollektives Feld\",\n        statement: \"Ich trage bewusst zur Entwicklung einer h\\xf6heren kollektiven Bewusstseinsstufe bei.\",\n        detail: \"Meine pers\\xf6nliche Entwicklung ist nicht nur pers\\xf6nlich. Jede Seele, die in Klarheit, Liebe und Integrit\\xe4t lebt, ver\\xe4ndert das Feld um sich herum. Ich bin ein Knotenpunkt in einem lebendigen Netz des Bewusstseins. Was ich in mir transformiere, wirkt nach au\\xdfen — in meine Familie, meinen Freundeskreis, meine Gemeinschaft, die Welt. Ich nehme diese Verantwortung ernst: Meine innere Arbeit ist mein gr\\xf6\\xdfter Beitrag zur Zivilisation.\"\n    },\n    {\n        id: 32,\n        sphere: \"Die neue Zivilisation\",\n        title: \"Verk\\xf6rpertes Beispiel\",\n        statement: \"Ich lebe als Beispiel daf\\xfcr, dass Seelenmeisterschaft im Alltag m\\xf6glich ist.\",\n        detail: \"Ich missioniere nicht. Ich predige nicht. Ich \\xfcberzeuge nicht durch Worte. Ich lebe. Das ist die wirksamste Form des Zeugnisses: ein Leben, das die Gebote nicht beschreibt, sondern verk\\xf6rpert. Wenn Menschen fragen, was mich tr\\xe4gt, was mich ruhig macht, was mir Kraft gibt — dann teile ich offen. Aber der erste und st\\xe4rkste Beweis ist das Leben selbst.\"\n    },\n    {\n        id: 33,\n        sphere: \"Die neue Zivilisation\",\n        title: \"Vision halten\",\n        statement: \"Ich halte die Vision einer Zivilisation aufrecht, die auf Seelenwachstum gegr\\xfcndet ist.\",\n        detail: \"Ich halte eine Vision in mir, die gr\\xf6\\xdfer ist als mein pers\\xf6nliches Leben: eine Menschheit, die sich erinnert, was sie ist. Eine Zivilisation, die nicht auf Konsum, Kontrolle und Konkurrenz gegr\\xfcndet ist, sondern auf Bewusstsein, Mitgef\\xfchl und Wahrheit. Diese Vision ist nicht naiv — sie ist die einzige, die dauerhaft tr\\xe4gt. Ich halte sie lebendig in mir — als inneres Bild, als Gebet, als Lebensrichtung.\"\n    },\n    {\n        id: 34,\n        sphere: \"Die neue Zivilisation\",\n        title: \"Einheitsbewusstsein\",\n        statement: \"Ich erkenne, dass alle Seelen aus derselben universellen Quelle entstammen — und kehre in meinem Bewusstsein t\\xe4glich zu dieser Einheit zur\\xfcck.\",\n        detail: \"Am Ende aller Wege steht eine Wahrheit: Wir sind eins. Alle Seelen — ob jung oder alt, ob lichtvoll oder noch tief in Dunkelheit — entstammen derselben universellen Quelle und kehren zu ihr zur\\xfcck. Die Trennung, die wir erleben, ist real als Erfahrung — und eine Illusion als Wesenswahrheit. Ich kehre t\\xe4glich zu dieser Einheit zur\\xfcck: in der Meditation, im Blick auf einen anderen Menschen, im Staunen vor dem Nachthimmel. Dieser R\\xfcckkehr ist das Ziel — und der Weg selbst.\"\n    },\n    {\n        id: 35,\n        sphere: \"Die neue Zivilisation\",\n        title: \"Lebendige Wahrheit\",\n        statement: \"Ich halte mein Weltbild lebendig — ich vertraue dem gegenw\\xe4rtigen Wissen und bleibe offen f\\xfcr tiefere Wahrheit.\",\n        detail: \"Ich halte die Erkenntnisse, auf denen mein Weg gr\\xfcndet, nicht f\\xfcr das letzte Wort der Wahrheit — sondern f\\xfcr das tiefste bisher verf\\xfcgbare Licht. Ich verfolge neue Forschung, neue Erfahrungen und neue Erkenntnisse mit Offenheit und Neugier. Was sich bew\\xe4hrt, bleibt. Was durch tiefere Wahrheit \\xfcberholt wird, lasse ich los — ohne Angst, ohne Krampf. Mein Fundament ist nicht ein festes Wissensgeb\\xe4ude, sondern die lebendige Ausrichtung auf Wahrheit selbst.\"\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./lib/principles.ts\n");

